import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import java.security.KeyStore
import javax.crypto.Cipher
import javax.crypto.KeyGenerator
import javax.crypto.SecretKey

class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var securePrefs: SharedPreferences
    private lateinit var usernameInput: EditText
    private lateinit var passwordInput: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button

    companion object {
        private const val PREFS_NAME = "secure_auth_prefs"
        private const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
        private const val KEY_AUTHENTICATED = "authenticated"
        private const val KEY_USERNAME = "username"
        private const val KEY_ALIAS = "biometric_key"
        private const val CORRECT_PASSWORD = "SecurePass123!"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        initializeSecurePreferences()
        initializeViews()
        checkAuthenticationStatus()
        setupBiometricPrompt()
        setupClickListeners()
    }

    private fun initializeSecurePreferences() {
        val masterKey = MasterKey.Builder(this)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        securePrefs = EncryptedSharedPreferences.create(
            this,
            PREFS_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    private fun initializeViews() {
        usernameInput = findViewById(R.id.usernameInput)
        passwordInput = findViewById(R.id.passwordInput)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)
    }

    private fun checkAuthenticationStatus() {
        if (isAuthenticated()) {
            navigateToMainActivity()
            return
        }

        if (isBiometricEnabled() && canUseBiometric()) {
            biometricButton.isEnabled = true
            showBiometricPrompt()
        } else {
            biometricButton.isEnabled = false
        }
    }

    private fun setupBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        this@LoginActivity,
                        "Authentication error: $errString",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    handleSuccessfulBiometricAuth()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Authentication failed. Try again.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Authentication")
            .setSubtitle("Log in using your fingerprint")
            .setDescription("Place your finger on the sensor to authenticate")
            .setNegativeButtonText("Use Password")
            .setConfirmationRequired(true)
            .build()
    }

    private fun setupClickListeners() {
        loginButton.setOnClickListener {
            handlePasswordLogin()
        }

        biometricButton.setOnClickListener {
            showBiometricPrompt()
        }
    }

    private fun showBiometricPrompt() {
        if (canUseBiometric()) {
            try {
                val cipher = getCipher()
                val secretKey = getOrCreateSecretKey()
                cipher.init(Cipher.ENCRYPT_MODE, secretKey)
                val cryptoObject = BiometricPrompt.CryptoObject(cipher)
                biometricPrompt.authenticate(promptInfo, cryptoObject)
            } catch (e: Exception) {
                biometricPrompt.authenticate(promptInfo)
            }
        } else {
            Toast.makeText(
                this,
                "Biometric authentication not available",
                Toast.LENGTH_SHORT
            ).show()
        }
    }

    private fun handlePasswordLogin() {
        val username = usernameInput.text.toString().trim()
        val password = passwordInput.text.toString()

        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please enter username and password", Toast.LENGTH_SHORT).show()
            return
        }

        if (validateCredentials(username, password)) {
            saveAuthenticationState(username)
            
            if (canUseBiometric() && !isBiometricEnabled()) {
                promptEnableBiometric()
            } else {
                navigateToMainActivity()
            }
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show()
            passwordInput.text.clear()
        }
    }

    private fun validateCredentials(username: String, password: String): Boolean {
        return password == CORRECT_PASSWORD && username.isNotEmpty()
    }

    private fun handleSuccessfulBiometricAuth() {
        Toast.makeText(this, "Biometric authentication successful", Toast.LENGTH_SHORT).show()
        
        val username = securePrefs.getString(KEY_USERNAME, "") ?: ""
        if (username.isNotEmpty()) {
            saveAuthenticationState(username)
            navigateToMainActivity()
        } else {
            Toast.makeText(this, "Please login with password first", Toast.LENGTH_SHORT).show()
        }
    }

    private fun saveAuthenticationState(username: String) {
        securePrefs.edit().apply {
            putBoolean(KEY_AUTHENTICATED, true)
            putString(KEY_USERNAME, username)
            apply()
        }
    }

    private fun promptEnableBiometric() {
        androidx.appcompat.app.AlertDialog.Builder(this)
            .setTitle("Enable Biometric Login")
            .setMessage("Would you like to enable fingerprint authentication for faster login?")
            .setPositiveButton("Enable") { _, _ ->
                enableBiometric()
                navigateToMainActivity()
            }
            .setNegativeButton("Not Now") { _, _ ->
                navigateToMainActivity()
            }
            .show()
    }

    private fun enableBiometric() {
        securePrefs.edit().putBoolean(KEY_BIOMETRIC_ENABLED, true).apply()
        Toast.makeText(this, "Biometric login enabled", Toast.LENGTH_SHORT).show()
    }

    private fun canUseBiometric(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)) {
            BiometricManager.BIOMETRIC_SUCCESS -> true
            else -> false
        }
    }

    private fun isAuthenticated(): Boolean {
        return securePrefs.getBoolean(KEY_AUTHENTICATED, false)
    }

    private fun isBiometricEnabled(): Boolean {
        return securePrefs.getBoolean(KEY_BIOMETRIC_ENABLED, false)
    }

    private fun navigateToMainActivity() {
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }

    private fun getOrCreateSecretKey(): SecretKey {
        val keyStore = KeyStore.getInstance("AndroidKeyStore")
        keyStore.load(null)

        if (!keyStore.containsAlias(KEY_ALIAS)) {
            val keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES,
                "AndroidKeyStore"
            )

            val keyGenParameterSpec = KeyGenParameterSpec.Builder(
                KEY_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
            )
                .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                .setUserAuthenticationRequired(true)
                .setInvalidatedByBiometricEnrollment(true)
                .build()

            keyGenerator.init(keyGenParameterSpec)
            return keyGenerator.generateKey()
        }

        return keyStore.getKey(KEY_ALIAS, null) as SecretKey
    }

    private fun getCipher(): Cipher {
        return Cipher.getInstance(
            KeyProperties.KEY_ALGORITHM_AES + "/" +
                    KeyProperties.BLOCK_MODE_CBC + "/" +
                    KeyProperties.ENCRYPTION_PADDING_PKCS7
        )
    }
}

class MainActivity : AppCompatActivity() {

    private lateinit var securePrefs: SharedPreferences
    private lateinit var welcomeText: android.widget.TextView
    private lateinit var logoutButton: Button
    private lateinit var disableBiometricButton: Button

    companion object {
        private const val PREFS_NAME = "secure_auth_prefs"
        private const val KEY_AUTHENTICATED = "authenticated"
        private const val KEY_USERNAME = "username"
        private const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        initializeSecurePreferences()
        initializeViews()
        displayUserInfo()
        setupClickListeners()
    }

    private fun initializeSecurePreferences() {
        val masterKey = MasterKey.Builder(this)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        securePrefs = EncryptedSharedPreferences.create(
            this,
            PREFS_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    private fun initializeViews() {
        welcomeText = findViewById(R.id.welcomeText)
        logoutButton = findViewById(R.id.logoutButton)
        disableBiometricButton = findViewById(R.id.disableBiometricButton)
    }

    private fun displayUserInfo() {
        val username = securePrefs.getString(KEY_USERNAME, "User") ?: "User"
        welcomeText.text = "Welcome, $username!"

        val biometricEnabled = securePrefs.getBoolean(KEY_BIOMETRIC_ENABLED, false)
        disableBiometricButton.isEnabled = biometricEnabled
        disableBiometricButton.text = if (biometricEnabled) {
            "Disable Biometric Login"
        } else {
            "Biometric Login Disabled"
        }
    }

    private fun setupClickListeners() {
        logoutButton.setOnClickListener {
            logout()
        }

        disableBiometricButton.setOnClickListener {
            disableBiometric()
        }
    }

    private fun logout() {
        securePrefs.edit().apply {
            putBoolean(KEY_AUTHENTICATED, false)
            apply()
        }

        startActivity(Intent(this, LoginActivity::class.java))
        finish()
    }

    private fun disableBiometric() {
        securePrefs.edit().apply {
            putBoolean(KEY_BIOMETRIC_ENABLED, false)
            apply()
        }

        Toast.makeText(this, "Biometric login disabled", Toast.LENGTH_SHORT).show()
        displayUserInfo()
    }
}